import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getValidatorIntelligence(withdrawalAddress) {
  const [balances, txns] = await Promise.all([
    client.BalanceService.getTokenBalancesForWalletAddress("eth-mainnet", withdrawalAddress),
    client.TransactionService.getTransactionsForAddressV3("eth-mainnet", withdrawalAddress),
  ]);
  const withdrawals = (txns.data?.items ?? []).filter(
    tx => tx.from_address === "0x00000000219ab540356cBB839Cbe05303d7705Fa"
  );
  return { withdrawalAddress, withdrawals, totalWithdrawn: withdrawals.reduce((s, t) => s + (t.value_quote ?? 0), 0) };
}
